  function renderCouponItem(coupon) {
    const left = daysUntil(coupon.expiry);
    const badgeClass = left === null ? '' : left < 0 ? 'bad' : left <= 7 ? 'warn' : 'good';
    const badgeText = left === null ? 'bez expirace' : left < 0 ? 'propadlý' : `${left} dní`;
    const isEditing = couponEditId === coupon.id;
    return `
      <div class="item">
        <div class="item-top">
          <div class="item-title">${escapeHtml(coupon.store)}</div>
          <span class="badge ${badgeClass}">${escapeHtml(badgeText)}</span>
        </div>
        <div class="item-meta">Kód: <strong>${escapeHtml(coupon.code)}</strong>${coupon.discount ? ` · ${escapeHtml(coupon.discount)}` : ''}${coupon.expiry ? ` · do ${formatDate(coupon.expiry)}` : ''}${coupon.note ? ` · ${escapeHtml(coupon.note)}` : ''}</div>
        <div class="item-actions coupon-actions">
          <button class="ghost-btn" type="button" data-action="toggle-coupon-edit" data-id="${escapeHtml(coupon.id)}">${isEditing ? 'Zavřít úpravu' : 'Upravit kód'}</button>
          <button class="ghost-btn" type="button" data-action="copy" data-value="${escapeHtml(coupon.code)}">Kopírovat kód</button>
          <button class="danger-btn" type="button" data-action="delete" data-collection="coupons" data-id="${escapeHtml(coupon.id)}">Smazat</button>
        </div>
        ${isEditing ? `
          <div class="coupon-inline-edit">
            <form data-form="update-coupon" data-id="${escapeHtml(coupon.id)}" class="compact-form">
              <div class="form-grid two">
                ${field('Obchod / služba', 'store', 'text', 'Alza / Temu / Allegro', true, coupon.store || '')}
                ${field('Kód', 'code', 'text', 'SLEVA10', true, coupon.code || '')}
                ${field('Sleva', 'discount', 'text', '10 % / 200 Kč', false, coupon.discount || '')}
                ${field('Platnost do', 'expiry', 'date', '', false, coupon.expiry || '')}
                ${field('Poznámka', 'note', 'text', 'volitelné', false, coupon.note || '')}
              </div>
              <div class="form-actions"><button class="primary-btn" type="submit">Uložit změny</button></div>
            </form>
          </div>
        ` : ''}
      </div>
    `;
  }



  function normalizeLoyaltyColor(value = '') {
    const key = normalizeKey(value || 'rose');
    return ['rose', 'blue', 'mint', 'amber', 'violet', 'slate'].includes(key) ? key : 'rose';
  }

  function normalizeLoyaltyCodeType(value = '') {
    const key = normalizeKey(value || 'barcode');
    return ['barcode', 'qr', 'text'].includes(key) ? key : 'barcode';
  }

  function loyaltyCardKey(card = {}) {
    return normalizeKey([card.store, card.cardNumber || card.code || card.barcode].filter(Boolean).join('|'));
  }

  function normalizeLoyaltyCard(item = {}) {
    const now = new Date().toISOString();
    const store = normalizeText(item.store || item.name || item.title || 'Karta');
    const cardNumber = normalizeText(item.cardNumber || item.card_number || item.number || item.code || item.barcode || '');
    return {
      id: normalizeText(item.id) || `loyalty-${uid()}`,
      householdId: normalizeText(item.householdId || item.household_id) || '',
      profileId: normalizeText(item.profileId || item.profile_id) || '',
      createdAt: normalizeText(item.createdAt || item.created_at) || now,
      updatedAt: normalizeText(item.updatedAt || item.updated_at) || normalizeText(item.createdAt || item.created_at) || now,
      store,
      cardNumber,
      codeType: normalizeLoyaltyCodeType(item.codeType || item.code_type),
      color: normalizeLoyaltyColor(item.color || item.theme),
      note: normalizeText(item.note || ''),
      photoDataUrl: normalizeText(item.photoDataUrl || item.photo_data_url || item.codeImage || item.image || ''),
      favorite: Boolean(item.favorite)
    };
  }

  function normalizeLoyaltyCards(items = []) {
    const byKey = new Map();
    (Array.isArray(items) ? items : []).forEach((item) => {
      const card = normalizeLoyaltyCard(item);
      if (!card.store && !card.cardNumber) return;
      const key = card.id || loyaltyCardKey(card);
      const existing = byKey.get(key);
      if (!existing || String(card.updatedAt || '').localeCompare(String(existing.updatedAt || '')) >= 0) byKey.set(key, card);
    });
    return [...byKey.values()].sort((a, b) => Number(Boolean(b.favorite)) - Number(Boolean(a.favorite)) || String(a.store).localeCompare(String(b.store), 'cs'));
  }

  function mergeLoyaltyCards(localItems = [], cloudItems = []) {
    const byKey = new Map();
    [...normalizeLoyaltyCards(localItems), ...normalizeLoyaltyCards(cloudItems)].forEach((card) => {
      const key = card.id || loyaltyCardKey(card);
      const altKey = loyaltyCardKey(card);
      const existingKey = byKey.has(key) ? key : (altKey && byKey.has(altKey) ? altKey : key);
      const existing = byKey.get(existingKey);
      if (!existing || String(card.updatedAt || '').localeCompare(String(existing.updatedAt || '')) >= 0) byKey.set(existingKey, card);
    });
    return normalizeLoyaltyCards([...byKey.values()]);
  }

  function getLoyaltyCards() {
    state.loyaltyCards = normalizeLoyaltyCards(state.loyaltyCards || []);
    return state.loyaltyCards;
  }

  function markLoyaltyCardsPending() {
    state.loyaltyCardsCloud = { ...(state.loyaltyCardsCloud || {}), pendingAt: new Date().toISOString(), errorAt: '', error: '' };
  }

  async function syncLoyaltyCardsToCloud() {
    if (!cloudReady()) {
      state.loyaltyCardsCloud = { ...(state.loyaltyCardsCloud || {}), errorAt: new Date().toISOString(), error: 'cloud-not-ready' };
      return false;
    }
    const ok = await cloudSaveHouseholdUiSettings(false);
    if (ok) {
      state.loyaltyCardsCloud = { ...(state.loyaltyCardsCloud || {}), loadedAt: new Date().toISOString(), pendingAt: '', errorAt: '', error: '' };
      saveState();
    } else {
      state.loyaltyCardsCloud = { ...(state.loyaltyCardsCloud || {}), errorAt: new Date().toISOString(), error: 'sync-failed' };
      saveState();
    }
    return ok;
  }

  function loyaltyCloudBadge() {
    const cloud = state.loyaltyCardsCloud || {};
    if (!cloudReady()) return { label: 'bez synchronizace', className: 'bad' };
    if (cloud.errorAt || cloud.error) return { label: 'problém synchronizace', className: 'bad' };
    if (cloud.pendingAt) return { label: 'čeká na odeslání', className: 'warn' };
    return { label: 'sdílená domácnost', className: 'good' };
  }

  function loyaltyCardSearchMatches(card, term = '') {
    const key = normalizeKey(term);
    if (!key) return true;
    return normalizeKey([card.store, card.cardNumber, card.note].filter(Boolean).join(' ')).includes(key);
  }

  function loyaltyCodeValue(value = '') {
    return normalizeText(value || '').trim() || '0000000000000';
  }

  function loyaltyUtf8Bytes(value = '') {
    const text = loyaltyCodeValue(value);
    if (typeof TextEncoder !== 'undefined') return Array.from(new TextEncoder().encode(text));
    return Array.from(text).map((char) => char.charCodeAt(0) & 0xFF);
  }

  const LOYALTY_QR_CAPACITY_L = {
    1: { data: 19, ecc: 7, align: [] },
    2: { data: 34, ecc: 10, align: [6, 18] },
    3: { data: 55, ecc: 15, align: [6, 22] },
    4: { data: 80, ecc: 20, align: [6, 26] },
    5: { data: 108, ecc: 26, align: [6, 30] }
  };

  function loyaltyQrGfMul(x, y) {
    let z = 0;
    for (let i = 7; i >= 0; i -= 1) {
      z = ((z << 1) ^ ((z >>> 7) * 0x11D)) & 0xFF;
      if (((y >>> i) & 1) !== 0) z ^= x;
    }
    return z & 0xFF;
  }

  function loyaltyQrRsDivisor(degree) {
    const result = Array(degree).fill(0);
    result[degree - 1] = 1;
    let root = 1;
    for (let i = 0; i < degree; i += 1) {
      for (let j = 0; j < degree; j += 1) {
        result[j] = loyaltyQrGfMul(result[j], root);
        if (j + 1 < degree) result[j] ^= result[j + 1];
      }
      root = loyaltyQrGfMul(root, 0x02);
    }
    return result;
  }

  function loyaltyQrRsRemainder(data, degree) {
    const divisor = loyaltyQrRsDivisor(degree);
    const result = Array(degree).fill(0);
    data.forEach((byte) => {
      const factor = byte ^ result.shift();
      result.push(0);
      divisor.forEach((coef, index) => {
        result[index] ^= loyaltyQrGfMul(coef, factor);
      });
    });
    return result;
  }

  function loyaltyQrAppendBits(bits, value, length) {
    for (let i = length - 1; i >= 0; i -= 1) bits.push((value >>> i) & 1);
  }

  function loyaltyQrFormatBits(eccLevelBits, mask) {
    const data = (eccLevelBits << 3) | mask;
    let bits = data << 10;
    for (let i = 14; i >= 10; i -= 1) {
      if (((bits >>> i) & 1) !== 0) bits ^= 0x537 << (i - 10);
    }
    return (((data << 10) | (bits & 0x3FF)) ^ 0x5412) & 0x7FFF;
  }

  function loyaltyQrMatrix(value = '') {
    const bytes = loyaltyUtf8Bytes(value);
    let version = 5;
    for (let v = 1; v <= 5; v += 1) {
      const meta = LOYALTY_QR_CAPACITY_L[v];
      if ((4 + 8 + bytes.length * 8) <= meta.data * 8) {
        version = v;
        break;
      }
    }
    const meta = LOYALTY_QR_CAPACITY_L[version] || LOYALTY_QR_CAPACITY_L[5];
    const dataBytes = bytes.slice(0, Math.max(0, meta.data - 2));
    const bits = [];
    loyaltyQrAppendBits(bits, 0x4, 4);
    loyaltyQrAppendBits(bits, dataBytes.length, 8);
    dataBytes.forEach((byte) => loyaltyQrAppendBits(bits, byte, 8));
    const maxBits = meta.data * 8;
    loyaltyQrAppendBits(bits, 0, Math.min(4, Math.max(0, maxBits - bits.length)));
    while (bits.length % 8) bits.push(0);
    const dataCodewords = [];
    for (let i = 0; i < bits.length; i += 8) dataCodewords.push(bits.slice(i, i + 8).reduce((acc, bit) => (acc << 1) | bit, 0));
    for (let pad = 0; dataCodewords.length < meta.data; pad += 1) dataCodewords.push(pad % 2 ? 0x11 : 0xEC);
    const codewords = [...dataCodewords, ...loyaltyQrRsRemainder(dataCodewords, meta.ecc)];
    const size = 21 + (version - 1) * 4;
    const modules = Array.from({ length: size }, () => Array(size).fill(false));
    const reserved = Array.from({ length: size }, () => Array(size).fill(false));
    const set = (x, y, dark, isFunction = true) => {
      if (x < 0 || y < 0 || x >= size || y >= size) return;
      modules[y][x] = Boolean(dark);
      if (isFunction) reserved[y][x] = true;
    };
    const finder = (x, y) => {
      for (let dy = -1; dy <= 7; dy += 1) {
        for (let dx = -1; dx <= 7; dx += 1) {
          const xx = x + dx;
          const yy = y + dy;
          if (xx < 0 || yy < 0 || xx >= size || yy >= size) continue;
          const inCore = dx >= 0 && dx <= 6 && dy >= 0 && dy <= 6;
          const dark = inCore && (dx === 0 || dx === 6 || dy === 0 || dy === 6 || (dx >= 2 && dx <= 4 && dy >= 2 && dy <= 4));
          set(xx, yy, dark, true);
        }
      }
    };
    finder(0, 0);
    finder(size - 7, 0);
    finder(0, size - 7);
    for (let i = 8; i < size - 8; i += 1) {
      set(i, 6, i % 2 === 0, true);
      set(6, i, i % 2 === 0, true);
    }
    (meta.align || []).forEach((cx) => (meta.align || []).forEach((cy) => {
      if (reserved[cy]?.[cx]) return;
      for (let dy = -2; dy <= 2; dy += 1) {
        for (let dx = -2; dx <= 2; dx += 1) {
          set(cx + dx, cy + dy, Math.max(Math.abs(dx), Math.abs(dy)) !== 1, true);
        }
      }
    }));
    for (let i = 0; i < 8; i += 1) {
      set(8, i, false, true);
      set(i, 8, false, true);
      set(size - 1 - i, 8, false, true);
      set(8, size - 1 - i, false, true);
    }
    set(8, size - 8, true, true);

    const dataBits = [];
    codewords.forEach((byte) => loyaltyQrAppendBits(dataBits, byte, 8));
    let bitIndex = 0;
    let upward = true;
    for (let right = size - 1; right > 0; right -= 2) {
      if (right === 6) right -= 1;
      for (let vert = 0; vert < size; vert += 1) {
        const y = upward ? size - 1 - vert : vert;
        for (let col = 0; col < 2; col += 1) {
          const x = right - col;
          if (reserved[y][x]) continue;
          let bit = bitIndex < dataBits.length ? dataBits[bitIndex] : 0;
          bitIndex += 1;
          if ((x + y) % 2 === 0) bit ^= 1;
          modules[y][x] = Boolean(bit);
        }
      }
      upward = !upward;
    }
    const format = loyaltyQrFormatBits(1, 0); // ECC low, mask 0
    const formatBit = (i) => ((format >>> i) & 1) !== 0;
    for (let i = 0; i <= 5; i += 1) set(8, i, formatBit(i), true);
    set(8, 7, formatBit(6), true);
    set(8, 8, formatBit(7), true);
    set(7, 8, formatBit(8), true);
    for (let i = 9; i < 15; i += 1) set(14 - i, 8, formatBit(i), true);
    for (let i = 0; i < 8; i += 1) set(size - 1 - i, 8, formatBit(i), true);
    for (let i = 8; i < 15; i += 1) set(8, size - 15 + i, formatBit(i), true);
    set(8, size - 8, true, true);
    return modules;
  }

  function loyaltyQrSvg(value = '', large = false) {
    const matrix = loyaltyQrMatrix(value);
    const size = matrix.length;
    const quiet = 4;
    const view = size + quiet * 2;
    const rects = [];
    matrix.forEach((row, y) => row.forEach((dark, x) => {
      if (dark) rects.push(`<rect x="${x + quiet}" y="${y + quiet}" width="1" height="1"/>`);
    }));
    return `<svg class="loyalty-code-svg loyalty-qr-svg ${large ? 'is-large' : ''}" viewBox="0 0 ${view} ${view}" role="img" aria-label="QR kód"><rect width="${view}" height="${view}" fill="#fff"/>${rects.join('')}</svg>`;
  }

  const LOYALTY_CODE128_PATTERNS = [
    '212222','222122','222221','121223','121322','131222','122213','122312','132212','221213','221312','231212','112232','122132','122231','113222','123122','123221','223211','221132','221231','213212','223112','312131','311222','321122','321221','312212','322112','322211','212123','212321','232121','111323','131123','131321','112313','132113','132311','211313','231113','231311','112133','112331','132131','113123','113321','133121','313121','211331','231131','213113','213311','213131','311123','311321','331121','312113','312311','332111','314111','221411','431111','111224','111422','121124','121421','141122','141221','112214','112412','122114','122411','142112','142211','241211','221114','413111','241112','134111','111242','121142','121241','114212','124112','124211','411212','421112','421211','212141','214121','412121','111143','111341','131141','114113','114311','411113','411311','113141','114131','311141','411131','211412','211214','211232','2331112'
  ];

  function loyaltyCode128Values(value = '') {
    const source = loyaltyCodeValue(value).replace(/[^\x20-\x7E]/g, '').slice(0, 80) || '0000000000000';
    const values = [104];
    [...source].forEach((char) => values.push(char.charCodeAt(0) - 32));
    const checksum = values.reduce((sum, code, index) => sum + (index === 0 ? code : code * index), 0) % 103;
    values.push(checksum, 106);
    return values;
  }

  function loyaltyBarcodeSvg(value = '', large = false) {
    const values = loyaltyCode128Values(value);
    let x = 10;
    const height = large ? 92 : 58;
    const bars = [];
    values.forEach((code) => {
      const pattern = LOYALTY_CODE128_PATTERNS[code] || LOYALTY_CODE128_PATTERNS[0];
      [...pattern].forEach((part, index) => {
        const width = Number(part) || 1;
        if (index % 2 === 0) bars.push(`<rect x="${x}" y="0" width="${width}" height="${height}"/>`);
        x += width;
      });
    });
    const viewWidth = x + 10;
    return `<svg class="loyalty-code-svg loyalty-barcode-svg ${large ? 'is-large' : ''}" viewBox="0 0 ${viewWidth} ${height}" role="img" aria-label="Čárový kód"><rect width="${viewWidth}" height="${height}" fill="#fff"/>${bars.join('')}</svg>`;
  }

  function loyaltyCodePreview(card = {}, size = 'small') {
    const large = size === 'large';
    const type = normalizeLoyaltyCodeType(card.codeType);
    if (type === 'qr') return `<div class="loyalty-code-render loyalty-code-render-qr ${large ? 'is-large' : ''}">${loyaltyQrSvg(card.cardNumber || card.store || 'qr', large)}</div>`;
    if (type === 'text') return `<div class="loyalty-text-code selectable-text ${large ? 'is-large' : ''}">${escapeHtml(card.cardNumber || 'bez čísla')}</div>`;
    return `<div class="loyalty-code-render loyalty-code-render-barcode ${large ? 'is-large' : ''}">${loyaltyBarcodeSvg(card.cardNumber || '0000000000000', large)}</div>`;
  }

  function loyaltyCodeTypeLabel(type = '') {
    const normalized = normalizeLoyaltyCodeType(type);
    if (normalized === 'qr') return 'QR kód';
    if (normalized === 'text') return 'Text';
    return 'Čárový kód';
  }

  function normalizeLoyaltyDetectedFormat(format = '') {
    const value = normalizeKey(format);
    if (value.includes('qr')) return 'qr';
    if (value.includes('code') || value.includes('ean') || value.includes('upc') || value.includes('aztec') || value.includes('data') || value.includes('pdf')) return 'barcode';
    return 'barcode';
  }

  function getLoyaltyScanState() {
    return loyaltyCardScan || { loading: false, dataUrl: '', detectedCode: '', detectedFormat: '', detectedText: '', error: '', source: '' };
  }

  function resetLoyaltyCardScan() {
    loyaltyCardScan = { loading: false, dataUrl: '', detectedCode: '', detectedFormat: '', detectedText: '', error: '', source: '' };
  }

  function normalizeLoyaltyAddDraft(data = {}) {
    return {
      store: normalizeText(data.store || ''),
      cardNumber: normalizeText(data.cardNumber || ''),
      codeType: normalizeLoyaltyCodeType(data.codeType || 'barcode'),
      color: normalizeLoyaltyColor(data.color || 'rose'),
      note: normalizeText(data.note || '')
    };
  }

  function saveLoyaltyAddDraftFromForm(form) {
    if (!form) return;
    const data = getFormData(form);
    loyaltyAddDraft = normalizeLoyaltyAddDraft({
      ...loyaltyAddDraft,
      ...data
    });
    loyaltyAddDetailsOpen = true;
  }

  function clearLoyaltyAddDraft() {
    loyaltyAddDraft = { store: '', cardNumber: '', codeType: 'barcode', color: 'rose', note: '' };
  }

  function renderLoyaltyScanPanel(scan = getLoyaltyScanState()) {
    const hasPreview = Boolean(scan?.dataUrl);
    const detected = normalizeText(scan?.detectedCode || '');
    const detectedText = normalizeText(scan?.detectedText || '');
    const sourceLabel = scan?.source === 'text' ? 'číslo z textu na fotce' : scan?.source === 'barcode' ? 'čárový/QR kód' : '';
    const status = scan?.loading
      ? 'Načítám fotku a zkouším najít kód i viditelné číslo…'
      : detected
        ? `Načteno ${sourceLabel ? `(${sourceLabel})` : ''}: ${detected}`
        : hasPreview
          ? 'Fotka je uložená jako podklad. Když se číslo nepřečetlo automaticky, opiš ho z náhledu do pole Číslo / kód karty.'
          : 'Vyfoť čárový/QR kód nebo kartu s viditelným číslem. Když to prohlížeč dovolí, číslo se doplní automaticky.';
    const statusClass = scan?.loading ? 'is-loading' : detected ? 'is-good' : hasPreview ? 'is-warn' : '';
    const textHint = detectedText && !detected ? `<span class="loyalty-detected-text">Na fotce jsem našel text: ${escapeHtml(detectedText)}</span>` : '';
    return `
      <div class="loyalty-scan-card ${statusClass}">
        <div class="loyalty-scan-copy">
          <strong>Vyfotit kartu / kód</strong>
          <span>${escapeHtml(status)}</span>
          ${textHint}
        </div>
        <div class="loyalty-scan-actions">
          <label class="ghost-btn loyalty-photo-btn" for="loyalty-card-photo-camera-input">Vyfotit</label>
          <input id="loyalty-card-photo-camera-input" class="sr-only-input" type="file" accept="image/*" capture="environment" data-loyalty-card-photo>
          <label class="ghost-btn loyalty-photo-btn" for="loyalty-card-photo-upload-input">Nahrát fotku</label>
          <input id="loyalty-card-photo-upload-input" class="sr-only-input" type="file" accept="image/*" data-loyalty-card-photo>
          ${hasPreview || detected || scan?.error ? '<button class="ghost-btn" type="button" data-action="clear-loyalty-scan">Vyčistit</button>' : ''}
        </div>
        ${hasPreview ? `<div class="loyalty-scan-preview"><img src="${escapeHtml(scan.dataUrl)}" alt="Náhled věrnostní karty nebo kódu"></div><div class="inline-note compact-note">Číslo z fotky můžeš rovnou opsat do pole níž. Uložená karta pak z čísla ukáže zvolený typ: čárový kód, QR nebo text.</div>` : ''}
      </div>`;
  }

  function readFileAsDataUrl(file) {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(String(reader.result || ''));
      reader.onerror = () => reject(reader.error || new Error('Soubor nejde načíst'));
      reader.readAsDataURL(file);
    });
  }

  function loadImageElement(src) {
    return new Promise((resolve, reject) => {
      const image = new Image();
      image.onload = () => resolve(image);
      image.onerror = () => reject(new Error('Obrázek nejde načíst'));
      image.src = src;
    });
  }

  async function compressLoyaltyImage(file) {
    const rawDataUrl = await readFileAsDataUrl(file);
    try {
      const image = await loadImageElement(rawDataUrl);
      const maxSize = 760;
      const ratio = Math.min(1, maxSize / Math.max(image.naturalWidth || image.width || 1, image.naturalHeight || image.height || 1));
      const width = Math.max(1, Math.round((image.naturalWidth || image.width || 1) * ratio));
      const height = Math.max(1, Math.round((image.naturalHeight || image.height || 1) * ratio));
      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d', { alpha: false });
      ctx.drawImage(image, 0, 0, width, height);
      return canvas.toDataURL('image/jpeg', 0.64);
    } catch (error) {
      console.warn('Loyalty image compression skipped', error);
      return rawDataUrl;
    }
  }

  function extractLoyaltyNumberFromText(text = '') {
    const source = normalizeText(text)
      .replace(/[O]/g, '0')
      .replace(/[Il|]/g, '1')
      .replace(/[–—]/g, '-');
    const numericCandidates = (source.match(/(?:\d[\s.\-]*){6,}/g) || [])
      .map((value) => value.replace(/[^0-9]/g, ''))
      .filter((value) => value.length >= 6);
    if (numericCandidates.length) return numericCandidates.sort((a, b) => b.length - a.length)[0];
    const alphaCandidates = (source.match(/[A-Z0-9][A-Z0-9\s.\-]{5,}/gi) || [])
      .map((value) => value.replace(/[^A-Z0-9]/gi, '').toUpperCase())
      .filter((value) => value.length >= 6);
    return alphaCandidates.sort((a, b) => b.length - a.length)[0] || '';
  }

  async function detectLoyaltyBarcodeFromImage(dataUrl) {
    const Detector = window.BarcodeDetector;
    if (typeof Detector !== 'function') return { code: '', format: '', error: 'BarcodeDetector není dostupný.' };
    try {
      const supported = typeof Detector.getSupportedFormats === 'function' ? await Detector.getSupportedFormats() : [];
      const detector = Array.isArray(supported) && supported.length ? new Detector({ formats: supported }) : new Detector();
      const image = await loadImageElement(dataUrl);
      const found = await detector.detect(image);
      const first = Array.isArray(found) ? found[0] : null;
      if (!first?.rawValue) return { code: '', format: '', error: 'Čárový/QR kód se z fotky nepovedlo načíst.' };
      return { code: normalizeText(first.rawValue), format: normalizeText(first.format || ''), source: 'barcode' };
    } catch (error) {
      console.warn('Loyalty barcode scan failed', error);
      return { code: '', format: '', error: 'Automatické čtení čárového/QR kódu se nepovedlo.' };
    }
  }

  async function detectLoyaltyTextFromImage(dataUrl) {
    const Detector = window.TextDetector;
    if (typeof Detector !== 'function') return { code: '', text: '', format: 'text', error: 'TextDetector není dostupný.' };
    try {
      const detector = new Detector();
      const image = await loadImageElement(dataUrl);
      const found = await detector.detect(image);
      const text = (Array.isArray(found) ? found : [])
        .map((item) => normalizeText(item.rawValue || item.text || ''))
        .filter(Boolean)
        .join(' ');
      const code = extractLoyaltyNumberFromText(text);
      if (!code) return { code: '', text, format: 'text', error: 'Text na fotce jsem našel, ale číslo karty z něj nešlo spolehlivě určit.' };
      return { code, text, format: 'text', source: 'text' };
    } catch (error) {
      console.warn('Loyalty text scan failed', error);
      return { code: '', text: '', format: 'text', error: 'Automatické čtení čísla z fotky se nepovedlo.' };
    }
  }

  async function detectLoyaltyCodeFromImage(dataUrl) {
    const barcode = await detectLoyaltyBarcodeFromImage(dataUrl);
    if (barcode.code) return barcode;
    const text = await detectLoyaltyTextFromImage(dataUrl);
    if (text.code) return text;
    return {
      code: '',
      format: '',
      detectedText: text.text || '',
      error: 'Fotku jsem uložil jako podklad, ale automatické čtení čísla tenhle prohlížeč nezvládl. Číslo opiš z náhledu ručně.'
    };
  }

  async function handleLoyaltyPhotoInput(input) {
    const file = input?.files?.[0];
    if (!file) return;
    loyaltyAddDetailsOpen = true;
    loyaltyCardScan = { loading: true, dataUrl: '', detectedCode: '', detectedFormat: '', detectedText: '', error: '', source: '' };
    render();
    try {
      const dataUrl = await compressLoyaltyImage(file);
      const detected = await detectLoyaltyCodeFromImage(dataUrl);
      loyaltyCardScan = {
        loading: false,
        dataUrl,
        detectedCode: detected.code || '',
        detectedFormat: normalizeLoyaltyDetectedFormat(detected.format || ''),
        detectedText: detected.detectedText || detected.text || '',
        error: detected.code ? '' : detected.error || 'Fotka uložená. Číslo doplň ručně z náhledu.',
        source: detected.source || ''
      };
      if (loyaltyCardScan.detectedCode) {
        loyaltyAddDraft = normalizeLoyaltyAddDraft({
          ...loyaltyAddDraft,
          cardNumber: loyaltyAddDraft.cardNumber || loyaltyCardScan.detectedCode,
          codeType: loyaltyCardScan.detectedFormat || loyaltyAddDraft.codeType || 'barcode'
        });
        showToast(loyaltyCardScan.source === 'text' ? 'Číslo karty načtené z textu na fotce' : 'Kód karty načtený z fotky');
      } else {
        showToast('Fotka uložená jako podklad. Číslo opiš z náhledu do pole níž.');
      }
    } catch (error) {
      console.error('Loyalty photo load failed', error);
      loyaltyCardScan = { loading: false, dataUrl: '', detectedCode: '', detectedFormat: '', detectedText: '', error: 'Fotku se nepovedlo načíst.', source: '' };
    } finally {
      input.value = '';
    }
    render();
  }

  async function handleLoyaltyEditPhotoInput(input) {
    const id = input?.dataset?.id || '';
    const file = input?.files?.[0];
    const card = state.loyaltyCards?.find((item) => item.id === id);
    if (!file || !card) return;
    showToast('Načítám fotku karty…');
    try {
      const dataUrl = await compressLoyaltyImage(file);
      const detected = await detectLoyaltyCodeFromImage(dataUrl);
      if (detected.code) {
        card.cardNumber = normalizeText(detected.code);
        card.codeType = normalizeLoyaltyDetectedFormat(detected.format || card.codeType || 'barcode');
      }
      // Fotka jde do IndexedDB, ne do state - viz putStoredLoyaltyPhoto.
      putStoredLoyaltyPhoto(card.id, dataUrl).catch((error) => console.warn('Loyalty photo IDB save failed', error));
      card.photoDataUrl = '';
      card.updatedAt = new Date().toISOString();
      markLoyaltyCardsPending();
      state.loyaltyCards = normalizeLoyaltyCards(state.loyaltyCards || []);
      touchState();
      saveState();
      render();
      await syncLoyaltyCardsToCloud();
      render();
      showToast(detected.code ? (cloudReady() ? 'Kód karty načtený a uložený do domácnosti' : 'Kód karty načtený lokálně') : 'Fotka uložená. Číslo můžeš upravit ručně.');
    } catch (error) {
      console.error('Loyalty edit photo load failed', error);
      showToast('Fotku se nepovedlo načíst.');
    } finally {
      input.value = '';
    }
  }

