  async function addLoyaltyCardFromForm(data, form) {
    saveLoyaltyAddDraftFromForm(form);
    const scan = getLoyaltyScanState();
    const draft = normalizeLoyaltyAddDraft({ ...loyaltyAddDraft, ...data });
    const card = normalizeLoyaltyCard({
      store: draft.store,
      cardNumber: draft.cardNumber || scan.detectedCode,
      codeType: draft.codeType || scan.detectedFormat,
      color: draft.color,
      note: draft.note,
      photoDataUrl: '',
      favorite: false,
      householdId: currentHouseholdId(),
      profileId: currentProfileId()
    });
    // Fotka ze skenu jde do IndexedDB pod id nové karty, ne do state.
    if (scan.dataUrl) putStoredLoyaltyPhoto(card.id, scan.dataUrl).catch((error) => console.warn('Loyalty photo IDB save failed', error));
    if (!card.store || !card.cardNumber) return showToast('Zadej obchod a číslo karty');
    state.loyaltyCards = normalizeLoyaltyCards(state.loyaltyCards || []);
    const existing = state.loyaltyCards.find((item) => loyaltyCardKey(item) === loyaltyCardKey(card));
    if (existing) {
      loyaltyCardEditId = existing.id;
      showToast('Tahle karta už existuje, otevřel jsem ji k úpravě');
      render();
      return;
    }
    state.loyaltyCards.push(card);
    state.loyaltyCards = normalizeLoyaltyCards(state.loyaltyCards);
    markLoyaltyCardsPending();
    touchState();
    saveState();
    form?.reset?.();
    resetLoyaltyCardScan();
    clearLoyaltyAddDraft();
    loyaltyAddDetailsOpen = false;
    render();
    await syncLoyaltyCardsToCloud();
    render();
    showToast(cloudReady() ? 'Věrnostní karta uložena' : 'Věrnostní karta uložena lokálně');
  }

  async function updateLoyaltyCardFromForm(id, data, form) {
    const card = state.loyaltyCards?.find((item) => item.id === id);
    if (!card) return showToast('Karta nenalezena');
    const updated = normalizeLoyaltyCard({
      ...card,
      store: data.store,
      cardNumber: data.cardNumber,
      codeType: data.codeType,
      color: data.color,
      note: data.note,
      photoDataUrl: card.photoDataUrl || '',
      updatedAt: new Date().toISOString()
    });
    Object.assign(card, updated);
    state.loyaltyCards = normalizeLoyaltyCards(state.loyaltyCards);
    loyaltyCardEditId = '';
    markLoyaltyCardsPending();
    touchState();
    saveState();
    form?.reset?.();
    render();
    await syncLoyaltyCardsToCloud();
    render();
    showToast(cloudReady() ? 'Věrnostní karta upravena' : 'Věrnostní karta upravena lokálně');
  }

  async function toggleLoyaltyFavorite(id) {
    const card = state.loyaltyCards?.find((item) => item.id === id);
    if (!card) return;
    card.favorite = !card.favorite;
    card.updatedAt = new Date().toISOString();
    state.loyaltyCards = normalizeLoyaltyCards(state.loyaltyCards);
    markLoyaltyCardsPending();
    touchState();
    saveState();
    render();
    await syncLoyaltyCardsToCloud();
    render();
  }

  async function deleteLoyaltyCard(id) {
    const card = state.loyaltyCards?.find((item) => item.id === id);
    if (!card) return;
    if (!window.confirm(`Smazat věrnostní kartu ${card.store || 'obchodu'}?`)) return;
    deleteStoredLoyaltyPhoto(id).catch(() => {});
    state.loyaltyCards = (state.loyaltyCards || []).filter((item) => item.id !== id);
    if (loyaltyCardEditId === id) loyaltyCardEditId = '';
    if (loyaltyCardPreviewId === id) loyaltyCardPreviewId = '';
    if (loyaltyCardMenuId === id) loyaltyCardMenuId = '';
    markLoyaltyCardsPending();
    touchState();
    saveState();
    render();
    await syncLoyaltyCardsToCloud();
    render();
    showToast(cloudReady() ? 'Karta smazána' : 'Karta smazána lokálně');
  }

