  function renderMoreModuleCard(module) {
    const stats = getModuleStats(module.id);
    return `
      <button class="item module-hub-item module-status-card more-module-card" type="button" data-nav="${module.id}">
        ${renderModuleIllustration(module.id, { size: 'card', slotClass: 'module-status-icon module-card-illustration-slot', extraClass: 'module-card-illustration', label: module.label })}
        <div class="more-module-copy">
          <strong>${escapeHtml(module.label)}</strong>
          <span>${stats.count} ${escapeHtml(stats.label)}</span>
        </div>
      </button>
    `;
  }

  function renderMoreModuleSection(section, moduleMap, usedIds) {
    const rows = section.ids
      .map((id) => moduleMap.get(id))
      .filter(Boolean);
    if (!rows.length) return '';
    rows.forEach((module) => usedIds.add(module.id));
    return `
      <section class="more-module-section">
        <div class="card-header compact-card-header">
          <div><h2>${escapeHtml(section.title)}</h2>${section.note ? `<p>${escapeHtml(section.note)}</p>` : ''}</div>
          <span class="badge">${rows.length}</span>
        </div>
        <div class="grid four more-module-grid">
          ${rows.map(renderMoreModuleCard).join('')}
        </div>
      </section>
    `;
  }

  function renderMore() {
    const modules = getVisibleModules().filter((module) => !['home', 'settings'].includes(module.id));
    const moduleMap = new Map(modules.map((module) => [module.id, module]));
    const usedIds = new Set();
    const sections = MODULE_CATEGORIES
      .filter((category) => category.id !== 'system')
      .map((category) => ({
        title: category.label,
        note: '',
        ids: modules.filter((module) => module.category === category.id).map((module) => module.id)
      }));
    const sectionHtml = sections.map((section) => renderMoreModuleSection(section, moduleMap, usedIds)).filter(Boolean).join('');
    const otherModules = modules.filter((module) => !usedIds.has(module.id));

    return `
      <div class="grid two more-hub-grid more-clean-hub">
        <section class="card desktop-span-2 more-settings-priority">
          <div class="card-header"><div><h2>Nastavení aplikace</h2><p>Domácnost, profily, zapnuté moduly, cloud, PWA a export/import.</p></div></div>
          <button class="item module-hub-item more-settings-card" type="button" data-nav="settings">
            ${renderModuleIllustration('settings', { size: 'card', slotClass: 'module-status-icon module-card-illustration-slot settings-module-icon-slot', extraClass: 'module-card-illustration settings-module-icon', label: 'Nastavení aplikace' })}
            <div class="more-module-copy">
              <strong>Nastavení aplikace</strong>
              <span>Správa domácnosti, modulů a vzhledu</span>
            </div>
            <span class="badge">otevřít</span>
          </button>
        </section>

        <section class="card desktop-span-2 more-modules-panel">
          <div class="card-header">
            <div><h2>Všechny funkce</h2><p>Spodní lišta zůstává krátká, tady jsou všechny zapnuté části aplikace.</p></div>
            <span class="badge">${modules.length}</span>
          </div>
          <div class="more-section-stack">
            ${sectionHtml || '<div class="empty">Zatím nejsou zapnuté žádné další moduly.</div>'}
            ${otherModules.length ? `
              <section class="more-module-section">
                <div class="card-header compact-card-header">
                  <div><h2>Ostatní</h2><p>Další zapnuté moduly.</p></div>
                  <span class="badge">${otherModules.length}</span>
                </div>
                <div class="grid four more-module-grid">
                  ${otherModules.map(renderMoreModuleCard).join('')}
                </div>
              </section>
            ` : ''}
          </div>
        </section>
      </div>
    `;
  }

